    "Wa-da-ra-bal-laa-hou-ma-tha-lan-qar-ya-tan-kaa-nat-'aa-mi-na-tan-mout-ma-'in-na-tan-ya'-tee-haa-riz-qou-haa-ra-gha-dan-min-koul-li-ma-kaa-nin-fa-ka-fa-rat-bi-an-'ou-mil-laa-hi-fa-a-dhaa-qa-hal-laa-hou-li-baa-sal-joo-'i-wal-khaw-fi-bi-maa-kaa-noo-yas-na-HOON",
